// Real-time data validation with performance optimization
const messages = inputs.messages || [];
const validMessages = [];
const invalidMessages = [];
const validationStats = {
  total_processed: 0,
  valid_count: 0,
  invalid_count: 0,
  validation_errors: {}
};

// Pre-compile validation functions for better performance
const validators = {
  required_fields: (data, fields) => {
    const missing = fields.filter(field => !data.hasOwnProperty(field) || data[field] === null || data[field] === undefined);
    return missing.length === 0 ? null : `Missing required fields: ${missing.join(', ')}`;
  },

  timestamp_validation: (data, field) => {
    const timestamp = new Date(data[field]);
    if (isNaN(timestamp.getTime())) return `Invalid timestamp format in ${field}`;

    const now = Date.now();
    const messageTime = timestamp.getTime();
    if (Math.abs(now - messageTime) > 24 * 60 * 60 * 1000) {
      return `Timestamp out of acceptable range: ${data[field]}`;
    }
    return null;
  },

  numeric_validation: (data, field) => {
    if (data[field] !== undefined && isNaN(Number(data[field]))) {
      return `Non-numeric value in ${field}: ${data[field]}`;
    }
    return null;
  },

  schema_validation: (data, schema) => {
    const errors = [];
    for (const [field, rules] of Object.entries(schema)) {
      if (rules.type === 'string' && typeof data[field] !== 'string') {
        errors.push(`${field} must be a string`);
      } else if (rules.type === 'number' && typeof data[field] !== 'number') {
        errors.push(`${field} must be a number`);
      }

      if (rules.min_length && data[field] && data[field].length < rules.min_length) {
        errors.push(`${field} must be at least ${rules.min_length} characters`);
      }
    }
    return errors.length > 0 ? errors.join(', ') : null;
  }
};

// Process messages in batch for performance
for (const message of messages) {
  try {
    const data = typeof message.value === 'string' ? JSON.parse(message.value) : message.value;
    const validationErrors = [];

    // Apply validation rules
    const requiredFields = inputs.validation_config?.required_fields || [];
    const timestampField = inputs.validation_config?.timestamp_field || 'timestamp';
    const numericFields = inputs.validation_config?.numeric_fields || [];
    const schema = inputs.validation_config?.schema || {};

    // Run validations
    const requiredError = validators.required_fields(data, requiredFields);
    if (requiredError) validationErrors.push(requiredError);

    if (data[timestampField]) {
      const timestampError = validators.timestamp_validation(data, timestampField);
      if (timestampError) validationErrors.push(timestampError);
    }

    for (const field of numericFields) {
      const numericError = validators.numeric_validation(data, field);
      if (numericError) validationErrors.push(numericError);
    }

    const schemaError = validators.schema_validation(data, schema);
    if (schemaError) validationErrors.push(schemaError);

    if (validationErrors.length === 0) {
      validMessages.push({
        ...data,
        _kafka_metadata: {
          topic: message.topic,
          partition: message.partition,
          offset: message.offset,
          timestamp: message.timestamp
        },
        _validation_timestamp: new Date().toISOString()
      });
      validationStats.valid_count++;
    } else {
      invalidMessages.push({
        original_message: data,
        validation_errors: validationErrors,
        kafka_metadata: {
          topic: message.topic,
          partition: message.partition,
          offset: message.offset
        },
        error_timestamp: new Date().toISOString()
      });

      validationStats.invalid_count++;
      validationErrors.forEach(error => {
        validationStats.validation_errors[error] = (validationStats.validation_errors[error] || 0) + 1;
      });
    }

  } catch (parseError) {
    invalidMessages.push({
      original_message: message,
      validation_errors: [`JSON parse error: ${parseError.message}`],
      error_timestamp: new Date().toISOString()
    });
    validationStats.invalid_count++;
  }

  validationStats.total_processed++;
}

return {
  valid_messages: validMessages,
  invalid_messages: invalidMessages,
  validation_stats: validationStats
};

// High-performance stream data transformation
const validMessages = inputs.valid_messages || [];
const transformationRules = inputs.transformation_config || {};
const transformedMessages = [];

// Pre-compile transformation functions
const transformations = {
  enrich_with_metadata: (data) => ({
    ...data,
    processing_timestamp: new Date().toISOString(),
    processing_batch_id: inputs.batch_id || 'unknown',
    data_source: data._kafka_metadata?.topic || 'unknown'
  }),

  calculate_derived_fields: (data, calculations) => {
    const derived = { ...data };
    for (const [field, expression] of Object.entries(calculations)) {
      try {
        // Safe evaluation of simple expressions
        if (expression.includes('+')) {
          const [left, right] = expression.split('+').map(s => s.trim());
          derived[field] = (parseFloat(data[left]) || 0) + (parseFloat(data[right]) || 0);
        } else if (expression.includes('*')) {
          const [left, right] = expression.split('*').map(s => s.trim());
          derived[field] = (parseFloat(data[left]) || 0) * (parseFloat(data[right]) || 0);
        } else if (expression.startsWith('count_')) {
          const sourceField = expression.replace('count_', '');
          derived[field] = Array.isArray(data[sourceField]) ? data[sourceField].length : 0;
        }
      } catch (error) {
        derived[field] = null;
        derived[`${field}_error`] = error.message;
      }
    }
    return derived;
  },

  normalize_geography: (data, geoFields) => {
    const normalized = { ...data };
    for (const field of geoFields) {
      if (data[field]) {
        // Simple geo normalization
        if (typeof data[field] === 'string') {
          normalized[field] = data[field].toLowerCase().trim();
        }
        // Add geo coordinates if available
        if (data[`${field}_lat`] && data[`${field}_lng`]) {
          normalized[`${field}_coordinates`] = {
            lat: parseFloat(data[`${field}_lat`]),
            lng: parseFloat(data[`${field}_lng`])
          };
        }
      }
    }
    return normalized;
  },

  categorize_data: (data, categoryRules) => {
    const categorized = { ...data };
    for (const [categoryField, rules] of Object.entries(categoryRules)) {
      let category = 'uncategorized';
      for (const rule of rules) {
        if (rule.condition && data[rule.field]) {
          const value = data[rule.field];
          switch (rule.operator) {
            case 'equals':
              if (value === rule.value) category = rule.category;
              break;
            case 'contains':
              if (value.toString().includes(rule.value)) category = rule.category;
              break;
            case 'greater_than':
              if (parseFloat(value) > parseFloat(rule.value)) category = rule.category;
              break;
            case 'less_than':
              if (parseFloat(value) < parseFloat(rule.value)) category = rule.category;
              break;
          }
          if (category !== 'uncategorized') break;
        }
      }
      categorized[categoryField] = category;
    }
    return categorized;
  }
};

// Apply transformations to each message
for (const message of validMessages) {
  let transformedMessage = { ...message };

  // Apply each transformation
  transformedMessage = transformations.enrich_with_metadata(transformedMessage);

  if (transformationRules.derived_calculations) {
    transformedMessage = transformations.calculate_derived_fields(
      transformedMessage, 
      transformationRules.derived_calculations
    );
  }

  if (transformationRules.geo_fields) {
    transformedMessage = transformations.normalize_geography(
      transformedMessage, 
      transformationRules.geo_fields
    );
  }

  if (transformationRules.category_rules) {
    transformedMessage = transformations.categorize_data(
      transformedMessage, 
      transformationRules.category_rules
    );
  }

  transformedMessages.push(transformedMessage);
}

return {
  transformed_messages: transformedMessages,
  transformation_stats: {
    input_count: validMessages.length,
    output_count: transformedMessages.length,
    transformation_timestamp: new Date().toISOString()
  }
};

// Real-time windowing and aggregation
const transformedMessages = inputs.transformed_messages || [];
const windowConfig = inputs.window_config || {};
const windowSizeMs = windowConfig.window_size_seconds * 1000 || 60000; // Default 1 minute
const windowType = windowConfig.type || 'tumbling'; // tumbling or sliding

// Initialize window state (in production, this would be persisted)
const windows = new Map();
const aggregationResults = [];

// Helper function to get window key
function getWindowKey(timestamp, windowSizeMs, windowType = 'tumbling') {
  const time = new Date(timestamp).getTime();
  if (windowType === 'tumbling') {
    return Math.floor(time / windowSizeMs) * windowSizeMs;
  } else {
    // Sliding window - multiple overlapping windows
    const slideInterval = windowSizeMs / 4; // 25% slide
    const windows = [];
    for (let i = 0; i < 4; i++) {
      const windowStart = Math.floor((time - i * slideInterval) / windowSizeMs) * windowSizeMs;
      windows.push(windowStart);
    }
    return windows;
  }
}

// Process each message into windows
for (const message of transformedMessages) {
  const timestamp = message.timestamp || message.processing_timestamp;
  const windowKeys = Array.isArray(getWindowKey(timestamp, windowSizeMs, windowType)) 
    ? getWindowKey(timestamp, windowSizeMs, windowType)
    : [getWindowKey(timestamp, windowSizeMs, windowType)];

  for (const windowKey of windowKeys) {
    if (!windows.has(windowKey)) {
      windows.set(windowKey, {
        window_start: new Date(windowKey).toISOString(),
        window_end: new Date(windowKey + windowSizeMs).toISOString(),
        messages: [],
        aggregations: {}
      });
    }

    windows.get(windowKey).messages.push(message);
  }
}

// Compute aggregations for each window
for (const [windowKey, windowData] of windows.entries()) {
  const messages = windowData.messages;

  if (messages.length === 0) continue;

  const aggregations = {
    // Basic counts
    message_count: messages.length,
    unique_sources: new Set(messages.map(m => m.data_source)).size,

    // Numeric aggregations
    numeric_stats: {},

    // Categorical distributions
    category_distributions: {},

    // Time-based metrics
    time_metrics: {
      first_message: Math.min(...messages.map(m => new Date(m.timestamp || m.processing_timestamp).getTime())),
      last_message: Math.max(...messages.map(m => new Date(m.timestamp || m.processing_timestamp).getTime())),
      message_rate_per_second: messages.length / (windowSizeMs / 1000)
    }
  };

  // Calculate numeric statistics
  const numericFields = windowConfig.numeric_fields || [];
  for (const field of numericFields) {
    const values = messages
      .map(m => parseFloat(m[field]))
      .filter(v => !isNaN(v));

    if (values.length > 0) {
      aggregations.numeric_stats[field] = {
        count: values.length,
        sum: values.reduce((a, b) => a + b, 0),
        avg: values.reduce((a, b) => a + b, 0) / values.length,
        min: Math.min(...values),
        max: Math.max(...values),
        stddev: Math.sqrt(values.reduce((sq, n) => sq + Math.pow(n - (values.reduce((a, b) => a + b, 0) / values.length), 2), 0) / values.length)
      };
    }
  }

  // Calculate categorical distributions
  const categoricalFields = windowConfig.categorical_fields || [];
  for (const field of categoricalFields) {
    const distribution = {};
    messages.forEach(m => {
      const value = m[field] || 'unknown';
      distribution[value] = (distribution[value] || 0) + 1;
    });
    aggregations.category_distributions[field] = distribution;
  }

  // Convert timestamps to readable format
  aggregations.time_metrics.first_message_iso = new Date(aggregations.time_metrics.first_message).toISOString();
  aggregations.time_metrics.last_message_iso = new Date(aggregations.time_metrics.last_message).toISOString();
  aggregations.time_metrics.window_duration_ms = aggregations.time_metrics.last_message - aggregations.time_metrics.first_message;

  aggregationResults.push({
    window_key: windowKey,
    window_start: windowData.window_start,
    window_end: windowData.window_end,
    aggregations: aggregations,
    computed_at: new Date().toISOString()
  });
}

return {
  windowed_aggregations: aggregationResults,
  window_stats: {
    total_windows: aggregationResults.length,
    total_messages_processed: transformedMessages.length,
    window_size_seconds: windowSizeMs / 1000,
    window_type: windowType
  }
};

// Real-time anomaly detection
const windowedAggregations = inputs.windowed_aggregations || [];
const anomalyThresholds = inputs.anomaly_config || {};
const detectedAnomalies = [];

// Historical baseline (in production, this would come from a ML model or database)
const historicalBaseline = {
  avg_message_count: anomalyThresholds.baseline_message_count || 1000,
  avg_message_rate: anomalyThresholds.baseline_message_rate || 16.67, // messages per second
  typical_source_count: anomalyThresholds.baseline_source_count || 5
};

for (const window of windowedAggregations) {
  const agg = window.aggregations;
  const anomalies = [];

  // Message volume anomaly detection
  const messageCountDeviation = Math.abs(agg.message_count - historicalBaseline.avg_message_count) / historicalBaseline.avg_message_count;
  if (messageCountDeviation > (anomalyThresholds.message_count_threshold || 0.5)) {
    anomalies.push({
      type: 'message_volume_anomaly',
      severity: messageCountDeviation > 0.8 ? 'high' : 'medium',
      current_value: agg.message_count,
      baseline_value: historicalBaseline.avg_message_count,
      deviation_percentage: (messageCountDeviation * 100).toFixed(2)
    });
  }

  // Message rate anomaly detection
  const rateDeviation = Math.abs(agg.time_metrics.message_rate_per_second - historicalBaseline.avg_message_rate) / historicalBaseline.avg_message_rate;
  if (rateDeviation > (anomalyThresholds.message_rate_threshold || 0.4)) {
    anomalies.push({
      type: 'message_rate_anomaly',
      severity: rateDeviation > 0.7 ? 'high' : 'medium',
      current_value: agg.time_metrics.message_rate_per_second.toFixed(2),
      baseline_value: historicalBaseline.avg_message_rate,
      deviation_percentage: (rateDeviation * 100).toFixed(2)
    });
  }

  // Source diversity anomaly
  const sourceDeviation = Math.abs(agg.unique_sources - historicalBaseline.typical_source_count) / historicalBaseline.typical_source_count;
  if (sourceDeviation > (anomalyThresholds.source_count_threshold || 0.3)) {
    anomalies.push({
      type: 'source_diversity_anomaly',
      severity: sourceDeviation > 0.6 ? 'high' : 'medium',
      current_value: agg.unique_sources,
      baseline_value: historicalBaseline.typical_source_count,
      deviation_percentage: (sourceDeviation * 100).toFixed(2)
    });
  }

  // Numeric field anomalies
  for (const [field, stats] of Object.entries(agg.numeric_stats || {})) {
    const fieldBaseline = anomalyThresholds.numeric_baselines?.[field];
    if (fieldBaseline) {
      const avgDeviation = Math.abs(stats.avg - fieldBaseline.avg) / fieldBaseline.avg;
      if (avgDeviation > (fieldBaseline.threshold || 0.3)) {
        anomalies.push({
          type: 'numeric_field_anomaly',
          field: field,
          metric: 'average',
          severity: avgDeviation > 0.6 ? 'high' : 'medium',
          current_value: stats.avg.toFixed(2),
          baseline_value: fieldBaseline.avg,
          deviation_percentage: (avgDeviation * 100).toFixed(2)
        });
      }
    }
  }

  if (anomalies.length > 0) {
    detectedAnomalies.push({
      window_key: window.window_key,
      window_start: window.window_start,
      window_end: window.window_end,
      anomaly_count: anomalies.length,
      anomalies: anomalies,
      detection_timestamp: new Date().toISOString(),
      overall_severity: anomalies.some(a => a.severity === 'high') ? 'high' : 'medium'
    });
  }
}

return {
  detected_anomalies: detectedAnomalies,
  anomaly_summary: {
    total_windows_checked: windowedAggregations.length,
    anomalous_windows: detectedAnomalies.length,
    high_severity_count: detectedAnomalies.filter(a => a.overall_severity === 'high').length,
    detection_timestamp: new Date().toISOString()
  }
};

